#include <stdio.h>
#include <stdlib.h>

int compare_desc(const void *a, const void *b) {
    int x = *(int *)b;
    int y = *(int *)a;
    return x - y;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, W; scanf("%d %d", &N, &W);
        int *arr = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        qsort(arr, N, sizeof(int), compare_desc);
        long long sum = 0;
        int used = 0;
        for (int i = 0; i < N; ++i) {
            sum += arr[i];
            ++used;
            if (sum >= W) break;
        }
        printf("%d\n", N - used);
        free(arr);
    }
    return 0;
}

